1064: /* reset codec link */
1065: static int azx_reset(struct azx *chip, int full_reset)
1066: {
1067: 	int count;
1068: 
1069: 	if (!full_reset)
1070: 		goto __skip;
1071: 
1072: 	/* clear STATESTS */
1073: 	azx_writeb(chip, STATESTS, STATESTS_INT_MASK);
1074: 
1075: 	/* reset controller */
1076: 	azx_writel(chip, GCTL, azx_readl(chip, GCTL) & ~ICH6_GCTL_RESET);
1077: 
1078: 	count = 50;
1079: 	while (azx_readb(chip, GCTL) && --count)
1080: 		msleep(1);
1081: 
1082: 	/* delay for >= 100us for codec PLL to settle per spec
1083: 	 * Rev 0.9 section 5.5.1
1084: 	 */
1085: 	msleep(1);
1086: 
1087: 	/* Bring controller out of reset */
1088: 	azx_writeb(chip, GCTL, azx_readb(chip, GCTL) | ICH6_GCTL_RESET);
1089: 
1090: 	count = 50;
1091: 	while (!azx_readb(chip, GCTL) && --count)
1092: 		msleep(1);
1093: 
1094: 	/* Brent Chartrand said to wait >= 540us for codecs to initialize */
1095: 	msleep(1);
1096: 
1097:       __skip:
1098: 	/* check to see if controller is ready */
1099: 	if (!azx_readb(chip, GCTL)) {
1100: 		snd_printd(SFX "azx_reset: controller not ready!\n");
1101: 		return -EBUSY;
1102: 	}
1103: 
1104: 	/* Accept unsolicited responses */
1105: 	if (!chip->single_cmd)
1106: 		azx_writel(chip, GCTL, azx_readl(chip, GCTL) |
1107: 			   ICH6_GCTL_UNSOL);
1108: 
1109: 	/* detect codecs */
1110: 	if (!chip->codec_mask) {
1111: 		chip->codec_mask = azx_readw(chip, STATESTS);
1112: 		snd_printdd(SFX "codec_mask = 0x%x\n", chip->codec_mask);
1113: 	}
1114: 
1115: 	return 0;
1116: }
