730: static void azx_init_cmd_io(struct azx *chip)
731: {
732: 	spin_lock_irq(&chip->reg_lock);
733: 	/* CORB set up */
734: 	chip->corb.addr = chip->rb.addr;
735: 	chip->corb.buf = (u32 *)chip->rb.area;
736: 	azx_writel(chip, CORBLBASE, (u32)chip->corb.addr);
737: 	azx_writel(chip, CORBUBASE, upper_32_bits(chip->corb.addr));
738: 
739: 	/* set the corb size to 256 entries (ULI requires explicitly) */
740: 	azx_writeb(chip, CORBSIZE, 0x02);
741: 	/* set the corb write pointer to 0 */
742: 	azx_writew(chip, CORBWP, 0);
743: 	/* reset the corb hw read pointer */
744: 	azx_writew(chip, CORBRP, ICH6_CORBRP_RST);
745: 	/* enable corb dma */
746: 	azx_writeb(chip, CORBCTL, ICH6_CORBCTL_RUN);
747: 
748: 	/* RIRB set up */
749: 	chip->rirb.addr = chip->rb.addr + 2048;
750: 	chip->rirb.buf = (u32 *)(chip->rb.area + 2048);
751: 	chip->rirb.wp = chip->rirb.rp = 0;
752: 	memset(chip->rirb.cmds, 0, sizeof(chip->rirb.cmds));
753: 	azx_writel(chip, RIRBLBASE, (u32)chip->rirb.addr);
754: 	azx_writel(chip, RIRBUBASE, upper_32_bits(chip->rirb.addr));
755: 
756: 	/* set the rirb size to 256 entries (ULI requires explicitly) */
757: 	azx_writeb(chip, RIRBSIZE, 0x02);
758: 	/* reset the rirb hw write pointer */
759: 	azx_writew(chip, RIRBWP, ICH6_RIRBWP_RST);
